#!/usr/bin/env python3
"""Fix: widen street_number column from 20 to 100 chars"""
import base64, os, sys
if not os.path.exists("backend/main.py"):
    print("Error: Run from ~/seller-portal"); sys.exit(1)
content = base64.b64decode("")
with open("backend/main.py", "wb") as f:
    f.write(content)
print(f"  Updated: backend/main.py ({len(content):,} bytes)")
print("\nNow run:")
print('  git add -A && git commit -m "Fix: widen street_number column to 100 chars" && git push')
